import{_ as s,o as a,c as t,e}from"./app-83da4608.js";const p={};function o(c,n){return a(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="_2-2-数据基础-数据库集成与-orm-typeorm-prisma" tabindex="-1"><a class="header-anchor" href="#_2-2-数据基础-数据库集成与-orm-typeorm-prisma" aria-hidden="true">#</a> 2.2 数据基础：数据库集成与 ORM（TypeORM / Prisma）</h1><p>在 AI Agent 应用中，数据是核心资产：原始数据、特征与中间结果、用户请求历史、任务状态、分析产物、评估与审计记录等都需要可靠的持久化。</p><p>本节聚焦如何在 Nest.js 后端建立数据基础，介绍两类常见 ORM 方案：TypeORM 与 Prisma，并给出在 Nest.js 中的典型集成方式与注意事项。</p><h2 id="_2-2-1-为什么使用-orm" tabindex="-1"><a class="header-anchor" href="#_2-2-1-为什么使用-orm" aria-hidden="true">#</a> 2.2.1 为什么使用 ORM？</h2><p>直接手写 SQL 能获得极高控制力，但在复杂业务中会带来重复、耦合与易错点。ORM（Object-Relational Mapping）提供了一层抽象：用面向对象的方式建模与访问数据，再由 ORM 生成参数化 SQL 并执行。</p><p>常见收益：</p><ul><li><strong>开发效率</strong>：CRUD 与查询构建器减少重复劳动</li><li><strong>类型与结构</strong>：与 TypeScript 配合可在编译期发现接口/字段错误</li><li><strong>可维护性</strong>：实体、迁移、仓库/服务层边界清晰</li><li><strong>安全性</strong>：默认参数化查询可显著降低 SQL 注入风险（但仍需避免拼接原始 SQL）</li></ul><h2 id="_2-2-2-数据库选型-以-postgresql-为例" tabindex="-1"><a class="header-anchor" href="#_2-2-2-数据库选型-以-postgresql-为例" aria-hidden="true">#</a> 2.2.2 数据库选型（以 PostgreSQL 为例）</h2><p>AI 数据分析的后端通常需要：</p><ul><li>大量结构化数据（用户、任务、权限、配置）</li><li>半结构化数据（模型输入输出、日志、评估指标等）</li></ul><p>PostgreSQL 常作为首选之一，原因包括：</p><ul><li>支持 <code>JSONB</code>、索引与丰富查询能力，适合存放半结构化数据</li><li>成熟的事务与一致性能力，适合任务状态与审计数据</li></ul><p>当然，MySQL、SQLite 也都能胜任部分场景：SQLite 适合本地开发或轻量部署；生产环境常用 PostgreSQL/MySQL。</p><h2 id="_2-2-3-方案-a-在-nest-js-中集成-typeorm" tabindex="-1"><a class="header-anchor" href="#_2-2-3-方案-a-在-nest-js-中集成-typeorm" aria-hidden="true">#</a> 2.2.3 方案 A：在 Nest.js 中集成 TypeORM</h2><p>Nest.js 提供官方集成包 <code>@nestjs/typeorm</code>。下面以 PostgreSQL 为例。</p><h3 id="步骤-1-安装依赖" tabindex="-1"><a class="header-anchor" href="#步骤-1-安装依赖" aria-hidden="true">#</a> 步骤 1：安装依赖</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> <span class="token function">add</span> @nestjs/typeorm typeorm pg @nestjs/config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="步骤-2-配置环境变量-示例" tabindex="-1"><a class="header-anchor" href="#步骤-2-配置环境变量-示例" aria-hidden="true">#</a> 步骤 2：配置环境变量（示例）</h3><p>在项目根目录的 <code>.env</code>：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token key attr-name">DATABASE_HOST</span><span class="token punctuation">=</span><span class="token value attr-value">localhost</span>
<span class="token key attr-name">DATABASE_PORT</span><span class="token punctuation">=</span><span class="token value attr-value">5432</span>
<span class="token key attr-name">DATABASE_USER</span><span class="token punctuation">=</span><span class="token value attr-value">your_username</span>
<span class="token key attr-name">DATABASE_PASSWORD</span><span class="token punctuation">=</span><span class="token value attr-value">your_password</span>
<span class="token key attr-name">DATABASE_NAME</span><span class="token punctuation">=</span><span class="token value attr-value">ai_analysis_db</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="步骤-3-配置数据库连接" tabindex="-1"><a class="header-anchor" href="#步骤-3-配置数据库连接" aria-hidden="true">#</a> 步骤 3：配置数据库连接</h3><p>推荐使用 <code>ConfigModule</code> + <code>TypeOrmModule.forRootAsync()</code>，避免在模块装配时直接散落读取 <code>p<wbr>rocess.env</code>，并便于测试与多环境切换。</p><p>这段配置写在哪里？</p><ul><li><strong>最常见（推荐入门）</strong>：直接写在后端项目的根模块 <code>src/app.module.ts</code> 的 <code>imports</code> 里。</li><li><strong>更清晰（项目变大后）</strong>：抽到单独的 <code>DatabaseModule</code>（例如 <code>src/database/database.module.ts</code>），再由 <code>AppModule</code> 导入这个模块。本文先用第一种写法，最直观。</li></ul><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> Module <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ConfigModule<span class="token punctuation">,</span> ConfigService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/config&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> TypeOrmModule <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/typeorm&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Module</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  imports<span class="token operator">:</span> <span class="token punctuation">[</span>
    ConfigModule<span class="token punctuation">.</span><span class="token function">forRoot</span><span class="token punctuation">(</span><span class="token punctuation">{</span> isGlobal<span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    TypeOrmModule<span class="token punctuation">.</span><span class="token function">forRootAsync</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      inject<span class="token operator">:</span> <span class="token punctuation">[</span>ConfigService<span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token function-variable function">useFactory</span><span class="token operator">:</span> <span class="token punctuation">(</span>config<span class="token operator">:</span> ConfigService<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token punctuation">{</span>
        type<span class="token operator">:</span> <span class="token string">&#39;postgres&#39;</span><span class="token punctuation">,</span>
        host<span class="token operator">:</span> config<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_HOST&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;localhost&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        port<span class="token operator">:</span> <span class="token function">Number</span><span class="token punctuation">(</span>config<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_PORT&#39;</span><span class="token punctuation">,</span> <span class="token number">5432</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        username<span class="token operator">:</span> config<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_USER&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        password<span class="token operator">:</span> config<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_PASSWORD&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        database<span class="token operator">:</span> config<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_NAME&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
        autoLoadEntities<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
        synchronize<span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span>
        logging<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;error&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AppModule</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>重要提示：</p><ul><li><code>synchronize: true</code> 仅建议用于本地开发/一次性原型验证；生产环境不要使用，避免误删/误改表结构。</li><li><code>autoLoadEntities: true</code> 会自动加载各模块通过 <code>TypeOrmModule.forFeature()</code> 注册的实体，避免维护 glob 路径。</li></ul><h3 id="步骤-4-使用-nest-cli-生成资源-推荐" tabindex="-1"><a class="header-anchor" href="#步骤-4-使用-nest-cli-生成资源-推荐" aria-hidden="true">#</a> 步骤 4：使用 Nest CLI 生成资源（推荐）</h3><p>最专业、高效的方式是使用 Nest CLI 的 <code>generate resource</code> 命令。它不仅会创建文件，还会自动生成模块（Module）、控制器（Controller）、服务（Service）、实体（Entity）和 DTO 的完整骨架，并自动配置依赖注入。</p><ol><li><strong>运行生成命令</strong>：</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在 backend 目录下运行</span>
<span class="token function">pnpm</span> dlx @nestjs/cli g resource analysis-results
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>交互式提示选择：</p><ul><li><strong>What transport layer do you use?</strong> -&gt; 选择 <code>REST API</code></li><li><strong>Would you like to generate CRUD entry points?</strong> -&gt; 选择 <code>Y</code> (Yes)</li></ul><p>这会自动创建 <code>src/analysis-results/</code> 目录及所有必要文件，并在 <code>app.module.ts</code> 中自动导入新模块。</p><ol start="2"><li><strong>编写实体代码</strong>：</li></ol><p>CLI 默认会在 <code>src/analysis-results/entities/</code> 下生成一个空的实体文件。请将其内容替换为以下代码：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// src/analysis-results/entities/analysis-result.entity.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Column<span class="token punctuation">,</span> CreateDateColumn<span class="token punctuation">,</span> Entity<span class="token punctuation">,</span> PrimaryGeneratedColumn<span class="token punctuation">,</span> UpdateDateColumn <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;typeorm&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Entity</span></span><span class="token punctuation">(</span><span class="token string">&#39;analysis_results&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisResult</span> <span class="token punctuation">{</span>
    <span class="token decorator"><span class="token at operator">@</span><span class="token function">PrimaryGeneratedColumn</span></span><span class="token punctuation">(</span><span class="token string">&#39;uuid&#39;</span><span class="token punctuation">)</span>
    id<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Column</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;text&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    taskName<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Column</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;jsonb&#39;</span><span class="token punctuation">,</span> nullable<span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    inputData<span class="token operator">?</span><span class="token operator">:</span> Record<span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token builtin">unknown</span><span class="token operator">&gt;</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Column</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;jsonb&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    outputData<span class="token operator">:</span> Record<span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token builtin">unknown</span><span class="token operator">&gt;</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Column</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;text&#39;</span><span class="token punctuation">,</span> nullable<span class="token operator">:</span> <span class="token boolean">true</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    modelId<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Column</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;varchar&#39;</span><span class="token punctuation">,</span> length<span class="token operator">:</span> <span class="token number">50</span><span class="token punctuation">,</span> <span class="token keyword">default</span><span class="token operator">:</span> <span class="token string">&#39;pending&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    status<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">CreateDateColumn</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;timestamp with time zone&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    createdAt<span class="token operator">:</span> Date<span class="token punctuation">;</span>

    <span class="token decorator"><span class="token at operator">@</span><span class="token function">UpdateDateColumn</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&#39;timestamp with time zone&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
    updatedAt<span class="token operator">:</span> Date<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>注意</strong>：<code>jsonb</code> 类型仅在 PostgreSQL 中可用。</p></blockquote><h3 id="步骤-5-注册实体与实现-crud" tabindex="-1"><a class="header-anchor" href="#步骤-5-注册实体与实现-crud" aria-hidden="true">#</a> 步骤 5：注册实体与实现 CRUD</h3><p>虽然 CLI 生成了模块，但 TypeORM 需要我们显式注册实体，才能让 <code>Repository</code> 正常工作。</p><ol><li><strong>在 Feature Module 中注册实体</strong>：</li></ol><p>打开 <code>src/analysis-results/analysis-results.module.ts</code>，添加 <code>TypeOrmModule.forFeature</code>：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> Module <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> TypeOrmModule <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/typeorm&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> AnalysisResultsService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./analysis-results.service&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> AnalysisResultsController <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./analysis-results.controller&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> AnalysisResult <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./entities/analysis-result.entity&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Module</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
    imports<span class="token operator">:</span> <span class="token punctuation">[</span>TypeOrmModule<span class="token punctuation">.</span><span class="token function">forFeature</span><span class="token punctuation">(</span><span class="token punctuation">[</span>AnalysisResult<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// &lt;--- 关键：注册实体</span>
    controllers<span class="token operator">:</span> <span class="token punctuation">[</span>AnalysisResultsController<span class="token punctuation">]</span><span class="token punctuation">,</span>
    providers<span class="token operator">:</span> <span class="token punctuation">[</span>AnalysisResultsService<span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisResultsModule</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li><strong>在 Service 中注入 Repository</strong>：</li></ol><p>打开 <code>src/analysis-results/analysis-results.service.ts</code>，注入 Repository 并实现增删改查：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span> Injectable <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> InjectRepository <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/typeorm&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Repository <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;typeorm&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> AnalysisResult <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./entities/analysis-result.entity&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisResultsService</span> <span class="token punctuation">{</span>
    <span class="token function">constructor</span><span class="token punctuation">(</span>
    <span class="token decorator"><span class="token at operator">@</span><span class="token function">InjectRepository</span></span><span class="token punctuation">(</span>AnalysisResult<span class="token punctuation">)</span>
    <span class="token keyword">private</span> <span class="token keyword">readonly</span> analysisResultRepository<span class="token operator">:</span> Repository<span class="token operator">&lt;</span>AnalysisResult<span class="token operator">&gt;</span><span class="token punctuation">,</span>
    <span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

    <span class="token keyword">async</span> <span class="token function">create</span><span class="token punctuation">(</span>data<span class="token operator">:</span> Partial<span class="token operator">&lt;</span>AnalysisResult<span class="token operator">&gt;</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span>AnalysisResult<span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> entity <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisResultRepository<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisResultRepository<span class="token punctuation">.</span><span class="token function">save</span><span class="token punctuation">(</span>entity<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">async</span> <span class="token function">findAll</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span>AnalysisResult<span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>analysisResultRepository<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果你希望对入参做验证，通常会配合 DTO + <code>class-validator</code>：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> <span class="token function">add</span> class-validator class-transformer
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_2-2-4-数据库迁移-migrations-实战指南" tabindex="-1"><a class="header-anchor" href="#_2-2-4-数据库迁移-migrations-实战指南" aria-hidden="true">#</a> 2.2.4 数据库迁移（Migrations）实战指南</h2><p>在生产环境中，严禁使用 <code>synchronize: true</code>，因为它可能导致数据丢失。标准的做法是使用 <strong>Migrations（迁移文件）</strong> 来管理数据库结构变更。</p><p>由于 TypeORM 的 CLI 需要独立的配置源，我们按以下步骤配置，确保新手也能一次跑通。</p><h3 id="步骤-1-创建-cli-专用配置文件" tabindex="-1"><a class="header-anchor" href="#步骤-1-创建-cli-专用配置文件" aria-hidden="true">#</a> 步骤 1：创建 CLI 专用配置文件</h3><p>在 <code>src</code> 目录下新建 <code>data-source.ts</code>，这个文件专门给 TypeORM CLI 使用，不影响 NestJS 应用本身的运行。</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// src/data-source.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> DataSource <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;typeorm&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ConfigService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/config&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> join <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;path&#39;</span><span class="token punctuation">;</span>

<span class="token comment">// 为了让 dotenv 在 TS 环境下安全运行</span>
<span class="token keyword">import</span> <span class="token string">&#39;dotenv/config&#39;</span><span class="token punctuation">;</span>

<span class="token comment">// 手动配置路径</span>
process<span class="token punctuation">.</span>env<span class="token punctuation">.</span><span class="token constant">DOTENV_CONFIG_PATH</span> <span class="token operator">=</span> <span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;../../.env&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 实例化一个临时的 ConfigService 供 TypeORM CLI 使用</span>
<span class="token keyword">const</span> configService <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ConfigService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> AppDataSource <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DataSource</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  type<span class="token operator">:</span> <span class="token string">&#39;postgres&#39;</span><span class="token punctuation">,</span>
  host<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_HOST&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;localhost&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  port<span class="token operator">:</span> <span class="token function">Number</span><span class="token punctuation">(</span>configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">number</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_PORT&#39;</span><span class="token punctuation">,</span> <span class="token number">5432</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  username<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_USER&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  password<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_PASSWORD&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  database<span class="token operator">:</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;DATABASE_NAME&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token comment">// 自动扫描实体文件</span>
  entities<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;**/*.entity{.ts,.js}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token comment">// 迁移文件存放路径</span>
  migrations<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;migrations/*{.ts,.js}&#39;</span><span class="token punctuation">)</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
  synchronize<span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token comment">// CLI 模式下必须为 false</span>
  logging<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="步骤-2-配置-package-json-命令" tabindex="-1"><a class="header-anchor" href="#步骤-2-配置-package-json-命令" aria-hidden="true">#</a> 步骤 2：配置 package.json 命令</h3><p>为了方便使用，我们在 <code>package.json</code> 的 <code>scripts</code> 中添加快捷命令。请将以下内容合并到你的 <code>scripts</code> 字段中：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token property">&quot;scripts&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
  <span class="token comment">// ... 其他原有命令</span>
  <span class="token property">&quot;typeorm&quot;</span><span class="token operator">:</span> <span class="token string">&quot;ts-node -r tsconfig-paths/register ./node_modules/typeorm/cli.js&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;migration:create&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm typeorm migration:create&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;migration:generate&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm typeorm migration:generate -d src/data-source.ts&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;migration:run&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm typeorm migration:run -d src/data-source.ts&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;migration:revert&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pnpm typeorm migration:revert -d src/data-source.ts&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="步骤-3-生成并运行迁移" tabindex="-1"><a class="header-anchor" href="#步骤-3-生成并运行迁移" aria-hidden="true">#</a> 步骤 3：生成并运行迁移</h3><blockquote><p><strong>提示</strong>：执行迁移命令前，请确保你的 PostgreSQL 数据库服务已经启动并且可以正常连接（配置的 host、port、user、password 和 database 必须正确）。如果没有安装本地数据库，你可以通过 Docker 快速启动一个：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在项目根目录创建一个 docker-compose.yml 文件</span>
<span class="token comment"># 然后运行以下命令启动数据库：</span>
<span class="token function">docker</span> compose up <span class="token parameter variable">-d</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><p>当你修改了实体（Entity）代码后（比如添加了一个字段），按照以下流程操作：</p><ol><li><strong>生成迁移文件</strong>： TypeORM 会自动对比实体代码和数据库当前的差异，生成 SQL 语句。</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 这里的 src/migrations/AddStatus 是迁移文件名，可以自定义</span>
<span class="token function">pnpm</span> migration:generate src/migrations/AddStatus
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><em>成功后，你会看到 <code>src/migrations/</code> 下多了一个时间戳开头的文件，里面包含了 <code>up</code> (升级) 和 <code>down</code> (回滚) 的 SQL 逻辑。</em></p><ol start="2"><li><strong>应用迁移</strong>： 将生成的 SQL 执行到数据库中。</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> migration:run
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li><strong>回滚（可选）</strong>： 如果刚才的迁移有问题，可以撤销最后一次迁移。</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> migration:revert
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><strong>常见问题</strong>：如果执行命令报错 <code>Connect ECONNREFUSED</code>，请检查 Docker 容器是否开启，或 <code>.env</code> 中的数据库端口配置是否正确。</p></blockquote><h2 id="_2-2-5-方案-b-prisma-概览" tabindex="-1"><a class="header-anchor" href="#_2-2-5-方案-b-prisma-概览" aria-hidden="true">#</a> 2.2.5 方案 B：Prisma（概览）</h2><p>Prisma 采用 Schema-First：先在 <code>schema.prisma</code> 定义数据模型，再生成类型安全的客户端代码。它的迁移工具链与开发体验通常更“现代化”。</p><h3 id="安装与初始化" tabindex="-1"><a class="header-anchor" href="#安装与初始化" aria-hidden="true">#</a> 安装与初始化</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">pnpm</span> <span class="token function">add</span> prisma @prisma/client
<span class="token function">pnpm</span> dlx prisma init
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="示例-schema-postgresql" tabindex="-1"><a class="header-anchor" href="#示例-schema-postgresql" aria-hidden="true">#</a> 示例 Schema（PostgreSQL）</h3><div class="language-prisma line-numbers-mode" data-ext="prisma"><pre class="language-prisma"><code>generator client {
  provider = &quot;prisma-client-js&quot;
}

datasource db {
  provider = &quot;postgresql&quot;
  url      = env(&quot;DATABASE_URL&quot;)
}

model AnalysisResult {
  id         String   @id @default(uuid())
  taskName   String
  inputData  Json?
  outputData Json
  modelId    String?
  status     String   @default(&quot;pending&quot;)
  createdAt  DateTime @default(now()) @map(&quot;created_at&quot;)
  updatedAt  DateTime @updatedAt @map(&quot;updated_at&quot;)

  @@map(&quot;analysis_results&quot;)
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="迁移与生成" tabindex="-1"><a class="header-anchor" href="#迁移与生成" aria-hidden="true">#</a> 迁移与生成</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 开发环境快速同步（不生成迁移文件）</span>
<span class="token function">pnpm</span> dlx prisma db push

<span class="token comment"># 推荐的开发迁移（生成并应用迁移）</span>
<span class="token function">pnpm</span> dlx prisma migrate dev <span class="token parameter variable">--name</span> init
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 Nest.js 中通常会封装一个 <code>PrismaService</code> 管理连接，并在业务服务中注入使用。</p><h2 id="_2-2-6-最佳实践-建议保留" tabindex="-1"><a class="header-anchor" href="#_2-2-6-最佳实践-建议保留" aria-hidden="true">#</a> 2.2.6 最佳实践（建议保留）</h2><ul><li><strong>环境变量管理</strong>：数据库凭证、连接串只放在服务端环境变量中，避免写入仓库。</li><li><strong>迁移优先</strong>：生产环境关闭 <code>synchronize</code>，用迁移控制变更并可回滚。</li><li><strong>事务与一致性</strong>：涉及多表更新或“写入 + 状态推进”的链路务必使用事务。</li><li><strong>索引与查询</strong>：对高频查询字段（例如 <code>status</code>、<code>createdAt</code>、业务维度字段）建立合适索引。</li><li><strong>错误处理与重试</strong>：连接失败、死锁、唯一键冲突要在服务层做清晰的错误语义与必要重试。</li><li><strong>日志与审计</strong>：开发环境可开启更详细 SQL 日志，生产环境建议记录慢查询、错误与关键审计事件。</li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>本节完成了“数据基础”这一层的关键认知与落地方式：</p><ul><li>理解为什么在 Nest.js 中使用 ORM</li><li>明确数据库选型要点（以 PostgreSQL 为例）</li><li>掌握 TypeORM 在 Nest.js 中的典型集成路径（配置、实体、仓库注入）</li><li>了解生产环境应采用迁移管理表结构</li><li>对 Prisma 的集成方式与迁移策略建立整体认知</li></ul><p>现在你的 Nest.js 应用已具备“可持续演进”的数据层基础，为后续 AI Agent 的任务记录、结果沉淀、评估与审计打下底座。下一节将讨论如何更安全地管理敏感配置（例如 API Key 等）。</p>`,83)])])}const l=s(p,[["render",o],["__file","2.2. 数据基础：数据库集成与ORM.html.vue"]]);export{l as default};
